import React from "react";

interface CouponCardProps {
  title: string;
  expiry: string;
  maxDiscount: number;
  discountRate: number;
  onUse: () => void;
}

const CouponCard: React.FC<CouponCardProps> = ({
  title,
  expiry,
  maxDiscount,
  discountRate,
  onUse,
}) => {
  return (
    <div className="relative bg-white text-center rounded-xl shadow-lg border border-dashed border-gray-400 overflow-hidden">
      {/* 왼쪽 구멍 */}
      <div className="absolute top-2/3 -left-4 w-8 h-8 bg-gray-100 rounded-full z-10 -translate-y-1/2"></div>

      {/* 오른쪽 구멍 */}
      <div className="absolute top-2/3 -right-4 w-8 h-8 bg-gray-100 rounded-full z-10 -translate-y-1/2"></div>

      <div className="p-4 flex flex-col items-center justify-center">
        <div className="flex flex-col items-center justify-start w-full">
          <h2 className="text-[16px] font-bold text-gray-800 text-left">{title}</h2>
          <p className="text-gray-600 text-[12px] text-left mt-2">
            {expiry}
            <br />
            (최대 {maxDiscount.toLocaleString()}원 할인)
          </p>
        </div>
        <div className="flex flex-row items-center justify-between w-full">
          <div className="mt-2 text-gray-600 font-semibold text-[12px]">사용 가능</div>
          <div className="mt-2 text-blue-600 font-bold text-[12px]">{discountRate}%</div>
        </div>
        <button
          className="mt-4 px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 transition"
          onClick={onUse}
        >
          쿠폰 사용하기
        </button>
      </div>
    </div>
  );
};

export default CouponCard;
